local UIPayShop = class("UIPayShop", IGUILayout)

function UIPayShop:onLoad()

    self.tabList = {}--tab列表
    self.selectTab = PayTabKind.NotKind--选中的tab类型
    self.selectItemId = 0 --选中的商品的Id
    self.itemsGridView = {}--商品列表



    self:initUI()
    self:initEvent()
    --print("+++++++++++++++++++")
    self:initTabList()
    --print("+++++++++++++++++++")
    self:addItemsGridView(true)
    --print("+++++++++++++++++++")


end

function UIPayShop:initUI()

    self.tvTitleCenterText = self:getChildWindow("LiftingSimulatorPayShop-TitleCenter-Text", GUIType.StaticText)
    self.tvTitleCenterText:SetText(Lang:getString("LiftingSimulatorPayShop.title.text"))
    self.btnTitleRightExit = self:getChildWindow("LiftingSimulatorPayShop-TitleRight-Exit", GUIType.Button)


    self.lvContentTabList = self:getChildWindow("LiftingSimulatorPayShop-ContentTab-List", GUIType.List)
    --self.gvContentItemsGridView = self:getChildWindow("LiftingSimulatorShop-ContentItems-GridView", GUIType.GridView)

    self.llContentItemsGridView = self:getChildWindow("LiftingSimulatorPayShop-ContentItems", GUIType.Layout)
    self.gvContentItemsGridView = IGUIGridView.new("LiftingSimulatorPayShop-ContentItems-GridView", self.llContentItemsGridView)
    self.gvContentItemsGridView:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 1, 0 })
    self.gvContentItemsGridView:setConfig(10, 10, 4)

    self.tvDetailTitle = self:getChildWindow("LiftingSimulatorPayShop-ContentDetail-Title", GUIType.StaticText)
    self.ivDetailItemIcon = self:getChildWindow("LiftingSimulatorPayShop-ContentDetail-ItemIcon", GUIType.StaticImage)
    self.tvDetailDescribe = self:getChildWindow("LiftingSimulatorPayShop-ContentDetail-Describe", GUIType.StaticText)

    self.btnDetailButton = self:getChildWindow("LiftingSimulatorPayShop-ContentDetail-Button", GUIType.Button)
    self.ivDetailGold = self:getChildWindow("LiftingSimulatorPayShop-ContentDetail-Button-Gold", GUIType.StaticImage)

end

function UIPayShop:initEvent()

    self.btnTitleRightExit:registerEvent(GUIEvent.ButtonClick, function()
        self:onButtonExit()
    end)

    self.btnDetailButton:registerEvent(GUIEvent.ButtonClick,function ()
        self:onDetailButton()
    end)

    self:registerEvent(PayShopItemClickEvent,function (itemId)
        self:onClickItem(itemId)
    end)

    self:registerEvent(PayShopToolbarClickEvent,function()
        self:onToolBarClick()
    end)

    self:registerEvent(PayDataInitEvent,function (payItemList, skinList, skinId)
        --print("IIIIIIIIIIIIIIIIIIIIIIIIIIIIII")
        self:initItemUpdate(payItemList,skinList,skinId)
    end)

    self:registerEvent(S2CBuySuccess, function(data)
        self:onBuySuccess(data)
    end)
    self:registerEvent(MainControlClickSkinEvent,function()
        self:onOpenSkin()
    end)

    self:registerEvent(MainControlClickVipEvent,function()
        self:onOpenPrivilege(Define.OpenPrivilegeType.ClickVip)
    end)

    self:registerEvent(PayShopItemClickButtonEvent,function (itemId)
        self:onItemClickButton(itemId)
    end)

    self:registerEvent(S2CLSEquipmentOrUnloadSkin, function(data)
        self:onEquipmentOrUnloadSkin(data)
    end)

    self:registerEvent(ToolBarGoldClickEvent, function ()
        self:onOpenPrivilege(Define.OpenPrivilegeType.ClickToolBarGold)
    end)

    self:registerEvent(MainControlCustomDialogClickEvent, function(tabKind,itemId)
        self:onCustomDialogClick(tabKind,itemId)
    end)


end

