function UIPayShop:onEquipmentOrUnloadSkin(data)

    local builder = DataBuilder.new():fromData(data)
    local id = builder:getNumberParam("id")
    local status = builder:getBoolParam("status")
    local oneSkin = SkinConfig:getSkinById(id)
    local tokenOneSkin = TokenSkinConfig:getSkinById(id)

    if oneSkin == nil and tokenOneSkin == nil then
        return
    end

    for i, value in pairs(SkinConfig:getSkins()) do
        if value.Status == PayItemBuyStatus.Using then
            value.Status = PayItemBuyStatus.Used
        end
    end

    if oneSkin then
        if status  == false then
            oneSkin.Status = PayItemBuyStatus.Used
        else
            oneSkin.Status = PayItemBuyStatus.Using
        end
    end


    self:addItemsGridView(false)

    if self.selectTab == PayTabKind.Skin then
        --self:addItemsGridView(false)
        self:onClickSkinItem(self.selectItemId)
    end


end

function UIPayShop:onOpenSkin()

    self:show()
    --self.selectTab = PayTabKind.Skin
    --self:addItemsGridView(true)
    self:onClickTab(PayTabKind.Skin, PayTabKind.Skin)
end

function UIPayShop:onOpenPrivilege(type)
    self.OpenPrivilegeType = type
    self:show()
    --self.selectTab = PayTabKind.Skin
    --self:addItemsGridView(true)
    self:onClickTab(PayTabKind.Privilege, PayTabKind.Privilege)
end

function UIPayShop:onBuySuccess(data)

    local builder = DataBuilder.new():fromData(data)
    local type = builder:getNumberParam("Type")
    local payItemList ={}
    local skinList = {}
    if type == Define.PayStoreItem.PayItem then
        local param = builder:getNumberParam("Param")
        --
        payItemList[tostring(param)] = 1
        --local str = string.format("GMHandler.onBuySuccess %d %d", type, param)
        --print(str)

    elseif type == Define.PayStoreItem.Skin then

        local param = builder:getNumberParam("Param")
        skinList[tostring(param)] = 1
        --local str = string.format("GMHandler.onBuySuccess %d %d", type, param)
        --print(str)

    end

    self:initItemUpdate(payItemList,skinList)

end
function UIPayShop:initItemUpdate(payItemList,skinList,skinId)


    --print(json.encode(payItemList))
    --print(json.encode(skinList))
    --print(skinId)

    for key, value in pairs(payItemList) do
        local onePrivilege =  PayItemConfig:getPayItemByType(key)
        if onePrivilege then
            onePrivilege.Status = PayItemBuyStatus.Used
            if onePrivilege.Type == Define.PayItemType.AutoWorkout then
                GUIMainControl:hideWorkoutAdvert()
            end
        end

    end

    for key, value in pairs(skinList) do
        local oneSkin = SkinConfig:getSkinById(tonumber(key))
        if oneSkin then
            oneSkin.Status = PayItemBuyStatus.Used
        end
    end

    local oneSkin = SkinConfig:getSkinById(tonumber(skinId))
    if oneSkin then
        oneSkin.Status = PayItemBuyStatus.Using
    end

    self:addItemsGridView(false)

    if self.selectTab == PayTabKind.Skin then
        --self:addItemsGridView(false)
        self:onClickSkinItem(self.selectItemId)
    end

    if self.selectTab == PayTabKind.Privilege then

        self:onClickPrivilegeItem(self.selectItemId)
    end
    MainControlPretendUpdateEvent:invoke()
    MainControlToolGoldUpdateEvent:invoke()
    RefreshPayFitnessEquipItemEvent:invoke()
end

function UIPayShop:initTabList()
    local i = 1
    for _, Value in pairs(PayShopTabsConfig:getTabs()) do

        local shopTab = GUIPayShopTab.new("LiftingSimulatorPayShopTab.json")

        self.tabList[i] = shopTab

        --加图集
        local strBg = "set:LiftingSimulatorPayShop1.json image:tabItemBg1"

        --local strIcon = "set:LiftingSimulatorShop1.json image:" .. Value.Icon

        --local strIcon = Value.Icon

        shopTab:initTab(Value.Id, Value.Type, strBg, Value.Icon, Value.Name)
        --GUIShopTab:initTab(TabId, Kind, Bg, Icon, Text)

        shopTab.ivTabsBg:registerEvent(GUIEvent.Click, function()
            self:onClickTab(Value.Id, Value.Type)
        end)

        shopTab:setArea({ 0, 0 }, { 0, 0 }, { 0, 180 }, { 0, 60 })

        self.lvContentTabList:AddItem(shopTab.root, false)
        --shopTab.root:SetSize({ 0, 130 }, { 0, 90 })
        i = i + 1
    end

    --将第一个Tab设置为选中状态
    if #self.tabList >= 1 then
        --加图集
        local strBg = "set:LiftingSimulatorPayShop1.json image:tabItemBg2"
        self.tabList[1]:changeSelectStatus(strBg, TabSelectStatus.Select)
        self.selectTab = self.tabList[1].kind
    end

end

function UIPayShop:addItemsGridView(flag)

    self.itemsGridView = {}
    self.gvContentItemsGridView:clearItems()

    if self.selectTab == PayTabKind.Privilege then
        self:addPrivilegeView(flag)
    end
    if self.selectTab == PayTabKind.Skin then
        self:addSkinView(flag)
    end

end

function UIPayShop:addView(kind, Value)

    local shopItem = GUIPayShopItem.new("LiftingSimulatorPayShopItem.json")

    local Bg = "set:LiftingSimulatorPayShop1.json image:itemBg1"

    shopItem:initItem(kind, Bg,Value)

    local contentWidth = self.gvContentItemsGridView:getWidth()
    local contentHeight = self.gvContentItemsGridView:getHeight()
    local itemWidth = (contentWidth - 30) / 4
    local itemHeight = (contentHeight - 10) / 2

    shopItem:setArea({ 0, 0 }, { 0, 0 }, { 0, itemWidth }, { 0, itemHeight })
    self.gvContentItemsGridView:addItem(shopItem)

    return shopItem

end

function UIPayShop:addPrivilegeView(flag)

    local i = 1

    --print(json.encode(FitnessEquipConfig:getFitnessEquips()))

    table.sort(PayItemConfig:getPayItems(), function(a, b)
        return a.sortId < b.sortId
    end)

    --print(json.encode(FitnessEquipConfig:getFitnessEquips()))

    for _, Value in pairs(PayItemConfig:getPayItems()) do

        --print("---------"..Value.Id.."-----------")
        --local ItemIcon = "set:LiftingSimulatorShop1.json image:equipOrSkillBg"
        self.itemsGridView[i] = self:addView(PayTabKind.Privilege, Value)
        i = i + 1
    end

    if flag and #self.itemsGridView >= 1 then
        self:onClickPrivilegeItem(self.itemsGridView[1].itemId)
        self.gvContentItemsGridView.root:ResetPos(0)
    end
end

function UIPayShop:addSkinView(flag)

    local i = 1

    table.sort(SkinConfig:getSkins(), function(a, b)
        return a.sortId < b.sortId
    end)

    for _, Value in pairs(SkinConfig:getSkins()) do

        --print("||||||||||||||||||||"..Value.Id.."|||||||||||||||")

        --local ItemIcon = "set:LiftingSimulatorShop1.json image:geneBg"
        self.itemsGridView[i] = self:addView(PayTabKind.Skin, Value)
        i = i + 1
    end
    if flag and #self.itemsGridView >= 1 then
        self:onClickSkinItem(self.itemsGridView[1].itemId)
        self.gvContentItemsGridView.root:ResetPos(0)
    end
end


--点击Tab
function UIPayShop:onClickTab(Id, Type)

    --print("---------onClickTab-----------")
    for _, shopTab in pairs(self.tabList) do
        if shopTab.tabId ~= Id then

            --加图集
            local strBg = "set:LiftingSimulatorPayShop1.json image:tabItemBg1"
            shopTab:changeSelectStatus(strBg, TabSelectStatus.NotSelect)

        else
            --加图集
            local strBg = "set:LiftingSimulatorPayShop1.json image:tabItemBg2"
            shopTab:changeSelectStatus(strBg, TabSelectStatus.Select)
            --self.selectTab = shopTab.kind
        end
    end

    if self.selectTab ~= Type then
        self.selectTab = Type
        self:addItemsGridView(true)
    end

end

function UIPayShop:selectItem(itemId)
    for _, shopItem in pairs(self.itemsGridView) do
        if shopItem.itemId ~= itemId then

            --加图集
            local strBg = "set:LiftingSimulatorPayShop1.json image:itemBg1"
            shopItem:changeSelectStatus(strBg, TabSelectStatus.NotSelect)

        else
            --加图集
            local strBg = "set:LiftingSimulatorPayShop1.json image:itemBg2"
            shopItem:changeSelectStatus(strBg, TabSelectStatus.Select)
        end

    end
end



function UIPayShop:getMoneyIconByMoneyType(Kind)

    local strMoneyIcon = ""
    if Kind == Define.MoneyType.SLGolds then
        --strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Golds)
        strMoneyIcon = "set:LiftingSimulatorShop1.json image:gold"
    end
    if Kind == Define.MoneyType.DiamondGolds2 then
        strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Diamonds)
        --strMoneyIcon = "set:LiftingSimulatorShop1.json image:DiamondBlues"
    end
    if Kind == Define.MoneyType.DiamondGolds1 then
        strMoneyIcon = PayHelper.getMoneyIcon(MoneyType.Diamonds)
        --strMoneyIcon = "set:LiftingSimulatorShop1.json image:DiamondGolds"
    end

    return strMoneyIcon

end

function UIPayShop:onClickItem(itemId)
    if self.selectTab == TabKind.FitnessEquip then
        self:onClickPrivilegeItem(itemId)
    end
    if self.selectTab == TabKind.Gene then
        self:onClickSkinItem(itemId)
    end
    --LogUtil.log(string.format("UIPayShop:onClickItem %d %d", itemId, self.OpenPrivilegeType))
end

function UIPayShop:onClickPrivilegeItem(itemId)

    local onePrivilege = PayItemConfig:getPayItemById(itemId)
    --print("onClickPrivilegeItem")
    --print(json.encode(onePrivilege))

    if onePrivilege == nil then
        return
    end
    self:selectItem(itemId)
    --加属性
    self.tvDetailTitle:SetText(Lang:getString(onePrivilege.Name))
    self.ivDetailItemIcon:SetImage(onePrivilege.Icon)
    self.tvDetailDescribe:SetText(Lang:getString(onePrivilege.Desc))

    self.btnDetailButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button")
    self.btnDetailButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button")

    if onePrivilege.Status == PayItemBuyStatus.Used then
        local strButtonTitle = "GUIPayShop_Have" --拥有
        self.btnDetailButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnDetailButton:SetText(Lang:getString(strButtonTitle))
        self.ivDetailGold:SetVisible(false)
        self.btnDetailButton:SetEnabled(false)
    else
        self.btnDetailButton:SetRenderOffset({ x = 20, y = 0 })
        self.btnDetailButton:SetText(tostring(onePrivilege.Price))
        local moneyIcon = self:getMoneyIconByMoneyType(onePrivilege.MoneyType)
        self.ivDetailGold:SetImage(moneyIcon)
        self.ivDetailGold:SetVisible(true)
        self.btnDetailButton:SetEnabled(true)
    end

    self.selectItemId = itemId

end

function UIPayShop:onClickSkinItem(itemId)

    local oneSkin = SkinConfig:getSkinById(itemId)
    --print("onClickSkinItem")
    --print(json.encode(oneSkin))
    if oneSkin == nil then
        return
    end



    self:selectItem(itemId)
    self.tvDetailTitle:SetText(Lang:getString(oneSkin.Name))
    self.ivDetailItemIcon:SetImage(oneSkin.Icon)
    self.tvDetailDescribe:SetText(Lang:getString(oneSkin.Desc))
    self.btnDetailButton:SetEnabled(true)

    self.btnDetailButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button")
    self.btnDetailButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button")

    if oneSkin.Status == PayItemBuyStatus.Used then
        self.btnDetailButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button3")
        self.btnDetailButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button3")
        local strButtonTitle = "GUIPayShop_Used" --使用
        self.btnDetailButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnDetailButton:SetText(Lang:getString(strButtonTitle))
        self.ivDetailGold:SetVisible(false)

    elseif oneSkin.Status == PayItemBuyStatus.Buy  then

        self.btnDetailButton:SetRenderOffset({ x = 20, y = 0 })
        self.btnDetailButton:SetText(tostring(oneSkin.Price))
        local moneyIcon = self:getMoneyIconByMoneyType(oneSkin.MoneyType)
        self.ivDetailGold:SetImage(moneyIcon)
        self.ivDetailGold:SetVisible(true)

    elseif oneSkin.Status == PayItemBuyStatus.Using then

        local strButtonTitle = "GUIPayShop_Unload" --卸下
        self.btnDetailButton:SetRenderOffset({ x = 0, y = 0 })
        self.btnDetailButton:SetText(Lang:getString(strButtonTitle))
        self.ivDetailGold:SetVisible(false)
        self.btnDetailButton:SetNormalImage("set:LiftingSimulatorPayShop1.json image:button2")
        self.btnDetailButton:SetPushedImage("set:LiftingSimulatorPayShop1.json image:button2")
    end

    self.selectItemId = itemId

end

function UIPayShop:onButtonExit()
    self:hide()
end

function UIPayShop:onToolBarClick()
    self:onOpenPrivilege(Define.OpenPrivilegeType.ClickVip)
end


function UIPayShop:onPrivilegeButton(itemId)

    local onePrivilege = PayItemConfig:getPayItemById(itemId)

    if onePrivilege == nil then
        return
    end

    if self.OpenPrivilegeType == Define.OpenPrivilegeType.ClickVip then
        local data = DataBuilder.new():addParam("ClickVip", "buy"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end

    if onePrivilege.Status == PayItemBuyStatus.Buy and (onePrivilege.MoneyType == Define.MoneyType.DiamondGolds1 or onePrivilege.MoneyType == Define.MoneyType.DiamondGolds2) then
        PayHelper.checkMoney(MoneyType.Diamonds, onePrivilege.Price, function(isEnough)
            if isEnough then
                --print("onFitnessEquipButton()")
                local data = DataBuilder.new():addParam("itemType", onePrivilege.Type):getData()
                PacketSender:sendLuaCommonData("BuyPayItem", data)
            end
        end)
    elseif onePrivilege.Status == PayItemBuyStatus.Buy then

        local data = DataBuilder.new():addParam("itemType", onePrivilege.Type):getData()
        PacketSender:sendLuaCommonData("BuyPayItem", data)
    end

end

function UIPayShop:onSkinButton(itemId)

    local oneSkin = SkinConfig:getSkinById(itemId)

    if oneSkin == nil then
        return
    end

    if self.OpenPrivilegeType == Define.OpenPrivilegeType.ClickVip then
        local data = DataBuilder.new():addParam("ClickVip", "buy"):getData()
        PacketSender:sendLuaCommonData("DoReport", data)
    end

    if oneSkin.Status == PayItemBuyStatus.Buy
            and (oneSkin.MoneyType == Define.MoneyType.DiamondGolds1 or oneSkin.MoneyType == Define.MoneyType.DiamondGolds2) then
        PayHelper.checkMoney(MoneyType.Diamonds, oneSkin.Price, function(isEnough)
            if isEnough then
                --print("onGeneButton()")
                local data = DataBuilder.new():addParam("id", oneSkin.Id):getData()
                PacketSender:sendLuaCommonData("BuySkin", data)
            end
        end)
    elseif oneSkin.Status == PayItemBuyStatus.Buy then
        local data = DataBuilder.new():addParam("id", oneSkin.Id):getData()
        PacketSender:sendLuaCommonData("BuySkin", data)
    elseif oneSkin.Status == PayItemBuyStatus.Used or oneSkin.Status == PayItemBuyStatus.Using then
        local skinId = -1
        if oneSkin.Status == PayItemBuyStatus.Used then
            skinId = oneSkin.Id
        end
        local data = DataBuilder.new():addParam("id", skinId):getData()
        PacketSender:sendLuaCommonData("EquipSkin", data)
    end
end


--购买、使用逻辑
function UIPayShop:onDetailButton()

    --print("0000000000000000000000")
    if self.selectTab == PayTabKind.Privilege then
        self:onPrivilegeButton(self.selectItemId)
    end
    if self.selectTab == PayTabKind.Skin then
        self:onSkinButton(self.selectItemId)
    end

end

function UIPayShop:onItemClickButton(itemId)

    --print("0000000000000000000000")
    if self.selectTab == PayTabKind.Privilege then
        self:onPrivilegeButton(itemId)
        self:onClickPrivilegeItem(itemId)
    end
    if self.selectTab == PayTabKind.Skin then
        self:onSkinButton(itemId)
        self:onClickSkinItem(itemId)
    end

end

function UIPayShop:onCustomDialogClick(tabKind,itemId)

    --print("0000000000000000000000")
    if tabKind == PayTabKind.Privilege then
        self:onPrivilegeButton(itemId)
        --self:onClickPrivilegeItem(itemId)
    end
    if tabKind == PayTabKind.Skin then
        self:onSkinButton(itemId)
        --self:onClickSkinItem(itemId)
    end

end

return UIPayShop


